// Map incoming payload to the notify emit-alert webhook format.
// Expected input:
//   { severity, category, title, body, source_service?, target_user_id?,
//     tags?, context? }
// severity: INFO | WARNING | ERROR | CRITICAL
// category: trade | risk | system | indicator
const payload = $input.item.json.body || $input.item.json;

const validSeverities = ['INFO', 'WARNING', 'ERROR', 'CRITICAL'];
const validCategories = ['trade', 'risk', 'system', 'indicator'];

const severity = (payload.severity || 'INFO').toUpperCase();
const category = (payload.category || 'system').toLowerCase();

if (!validSeverities.includes(severity)) {
  throw new Error(`Invalid severity: ${severity}. Must be one of ${validSeverities.join(', ')}`);
}
if (!validCategories.includes(category)) {
  throw new Error(`Invalid category: ${category}. Must be one of ${validCategories.join(', ')}`);
}
if (!payload.message && !payload.body) {
  throw new Error('Missing required field: message or body');
}

return {
  json: {
    severity,
    category,
    title: payload.title || `${category} alert`,
    message: payload.message || payload.body,
    source_service: payload.source_service || 'n8n',
    target_user_id: payload.target_user_id || '',
    tags: Array.isArray(payload.tags) ? payload.tags : [],
    context: payload.context || {},
    correlation_id: payload.correlation_id || '',
  }
};
